#include "mlpa/analyzers/Analyzers.h"
#include <clang/AST/RecursiveASTVisitor.h>
namespace mlpa { namespace { SourceLocation loc(const clang::SourceManager&s,clang::SourceLocation l){auto p=s.getPresumedLoc(l);return{p.isValid()?p.getFilename():"<unknown>",p.isValid()?p.getLine():0,p.isValid()?p.getColumn():0};} void issue(AnalysisResult&r,const clang::SourceManager&s,clang::SourceLocation l,std::string id,Severity sev,std::string title,std::string exp,std::string fix){r.issues.push_back({std::move(id),Category::Performance,sev,loc(s,l),std::move(title),std::move(exp),std::move(fix)});} bool isStl(clang::QualType t, llvm::StringRef n){return t.getAsString().find(("std::"+n.str()).str())!=std::string::npos;} class V: public clang::RecursiveASTVisitor<V>{public:V(clang::ASTContext&c,AnalysisResult&r):ctx(c),res(r),sm(c.getSourceManager()){} bool VisitParmVarDecl(clang::ParmVarDecl*p){auto t=p->getType(); if(!t->isReferenceType()&&(isStl(t,"vector")||isStl(t,"map")||isStl(t,"unordered_map")||isStl(t,"string"))) issue(res,sm,p->getLocation(),"PERF001",Severity::Medium,"Expensive pass-by-value","Large standard-library objects passed by value can copy data on every call.","Pass by const reference unless the function intentionally takes ownership."); return true;} bool VisitCXXForRangeStmt(clang::CXXForRangeStmt*f){ if(auto*v=llvm::dyn_cast_or_null<clang::VarDecl>(f->getLoopVariable())) if(!v->getType()->isReferenceType()) issue(res,sm,v->getLocation(),"PERF003",Severity::Low,"Inefficient range loop copy","The loop variable is copied for each element.","Use const auto& or auto& for non-trivial element types."); return true;} bool VisitVarDecl(clang::VarDecl*d){ if(isStl(d->getType(),"map")) issue(res,sm,d->getLocation(),"PERF005",Severity::Low,"Consider unordered_map","std::map keeps keys ordered and has logarithmic lookup cost.","Use std::unordered_map when deterministic key ordering is not required."); return true;} bool VisitCallExpr(clang::CallExpr*c){ if(auto*m=llvm::dyn_cast_or_null<clang::CXXMemberCallExpr>(c)){auto name=m->getMethodDecl()?m->getMethodDecl()->getNameAsString():""; if(name=="push_back") issue(res,sm,c->getBeginLoc(),"PERF004",Severity::Low,"Check vector reserve","Repeated push_back can reallocate when capacity is not reserved.","Call reserve() when the final or approximate size is known.");} return true;}private:clang::ASTContext&ctx;AnalysisResult&res;const clang::SourceManager&sm;};}
void PerformanceAnalyzer::analyze(clang::ASTContext &context, AnalysisResult &result){V(context,result).TraverseDecl(context.getTranslationUnitDecl());}}
